  `violation_flag` tinyint(1) DEFAULT 0,
  `profile_image` varchar(255) DEFAULT NULL,
  `daily_rate` decimal(10,2) DEFAULT 600.00,
  `performance_allowance` decimal(10,2) DEFAULT 0.00,
  `branch_id` int(11) DEFAULT NULL,
  `face_embedding` text DEFAULT NULL,
  `face_image_url` varchar(255) DEFAULT NULL,
  `face_enrolled_at` timestamp NULL DEFAULT NULL,
  `has_deduction` tinyint(4) DEFAULT 1,
  PRIMARY KEY (`id`),
  UNIQUE KEY `employee_code` (`employee_code`),
  UNIQUE KEY `email` (`email`),
  KEY `fk_employees_branch` (`branch_id`)
) ENGINE=MyISAM AUTO_INCREMENT=172 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


